# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import secrets
import time
from functools import wraps
import jwt
from datetime import datetime, timedelta

app = Flask(__name__)
app.config['SECRET_KEY'] = secrets.token_hex(32)

# In-memory storage for nonces and sessions (use Redis in production)
nonces = {}
authenticated_sessions = {}

# Session expiry time
SESSION_EXPIRY = 3600  # 1 hour
NONCE_EXPIRY = 300  # 5 minutes

w3 = Web3()


def cleanup_expired_nonces():
    current_time = time.time()
    expired = [addr for addr, data in nonces.items() 
               if current_time - data['timestamp'] > NONCE_EXPIRY]
    for addr in expired:
        del nonces[addr]


def cleanup_expired_sessions():
    current_time = time.time()
    expired = [token for token, data in authenticated_sessions.items() 
               if current_time > data['expiry']]
    for token in expired:
        del authenticated_sessions[token]


def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token:
            return jsonify({'error': 'No authorization token provided'}), 401
        
        if token.startswith('Bearer '):
            token = token[7:]
        
        cleanup_expired_sessions()
        
        if token not in authenticated_sessions:
            return jsonify({'error': 'Invalid or expired token'}), 401
        
        if time.time() > authenticated_sessions[token]['expiry']:
            del authenticated_sessions[token]
            return jsonify({'error': 'Token expired'}), 401
        
        request.wallet_address = authenticated_sessions[token]['address']
        return f(*args, **kwargs)
    
    return decorated_function


@app.route('/api/auth/nonce', methods=['POST'])
def get_nonce():
    data = request.get_json()
    
    if not data or 'address' not in data:
        return jsonify({'error': 'Address is required'}), 400
    
    address = data['address']
    
    if not Web3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    address = Web3.to_checksum_address(address)
    
    cleanup_expired_nonces()
    
    nonce = secrets.token_hex(16)
    nonces[address] = {
        'nonce': nonce,
        'timestamp': time.time()
    }
    
    return jsonify({
        'nonce': nonce,
        'message': f'Sign this message to authenticate with our service.\n\nNonce: {nonce}\nTimestamp: {int(time.time())}'
    }), 200


@app.route('/api/auth/verify', methods=['POST'])
def verify_signature():
    data = request.get_json()
    
    if not data or 'address' not in data or 'signature' not in data or 'message' not in data:
        return jsonify({'error': 'Address, signature, and message are required'}), 400
    
    address = data['address']
    signature = data['signature']
    message = data['message']
    
    if not Web3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    address = Web3.to_checksum_address(address)
    
    cleanup_expired_nonces()
    
    if address not in nonces:
        return jsonify({'error': 'No nonce found for this address. Please request a new nonce.'}), 400
    
    stored_nonce = nonces[address]['nonce']
    
    if stored_nonce not in message:
        return jsonify({'error': 'Invalid nonce in message'}), 400
    
    try:
        message_hash = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(message_hash, signature=signature)
        
        if recovered_address.lower() != address.lower():
            return jsonify({'error': 'Signature verification failed'}), 401
        
        del nonces[address]
        
        token = secrets.token_urlsafe(32)
        authenticated_sessions[token] = {
            'address': address,
            'expiry': time.time() + SESSION_EXPIRY,
            'created_at': time.time()
        }
        
        jwt_token = jwt.encode({
            'address': address,
            'exp': datetime.utcnow() + timedelta(seconds=SESSION_EXPIRY),
            'iat': datetime.utcnow()
        }, app.config['SECRET_KEY'], algorithm='HS256')
        
        return jsonify({
            'success': True,
            'token': token,
            'jwt': jwt_token,
            'address': address,
            'expiresIn': SESSION_EXPIRY
        }), 200
        
    except Exception as e:
        return jsonify({'error': f'Signature verification failed: {str(e)}'}), 401


@app.route('/api/auth/verify-jwt', methods=['POST'])
def verify_jwt_token():
    data = request.get_json()
    
    if not data or 'jwt' not in data:
        return jsonify({'error': 'JWT token is required'}), 400
    
    try:
        payload = jwt.decode(
            data['jwt'],
            app.config['SECRET_KEY'],
            algorithms=['HS256']
        )
        
        return jsonify({
            'success': True,
            'address': payload['address'],
            'exp': payload['exp']
        }), 200
        
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    except jwt.InvalidTokenError as e:
        return jsonify({'error': f'Invalid token: {str(e)}'}), 401


@app.route('/api/auth/logout', methods=['POST'])
@require_auth
def logout():
    token = request.headers.get('Authorization')
    if token and token.startswith('Bearer '):
        token = token[7:]
    
    if token in authenticated_sessions:
        del authenticated_sessions[token]
    
    return jsonify({'success': True, 'message': 'Logged out successfully'}), 200


@app.route('/api/protected/profile', methods=['GET'])
@require_auth
def get_profile():
    return jsonify({
        'address': request.wallet_address,
        'authenticated': True,
        'message': 'This is a protected endpoint'
    }), 200


@app.route('/api/auth/status', methods=['GET'])
@require_auth
def auth_status():
    token = request.headers.get('Authorization')
    if token and token.startswith('Bearer '):
        token = token[7:]
    
    session_data = authenticated_sessions.get(token, {})
    
    return jsonify({
        'authenticated': True,
        'address': request.wallet_address,
        'expiresAt': session_data.get('expiry'),
        'timeRemaining': int(session_data.get('expiry', 0) - time.time())
    }), 200


@app.route('/api/signature/verify-custom', methods=['POST'])
def verify_custom_signature():
    data = request.get_json()
    
    required_fields = ['address', 'message', 'signature']
    if not all(field in data for field in required_fields):
        return jsonify({'error': 'Address, message, and signature are required'}), 400
    
    address = data['address']
    message = data['message']
    signature = data['signature']
    
    if not Web3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    address = Web3.to_checksum_address(address)
    
    try:
        message_hash = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(message_hash, signature=signature)
        
        is_valid = recovered_address.lower() == address.lower()
        
        return jsonify({
            'valid': is_valid,
            'recoveredAddress': recovered_address,
            'providedAddress': address
        }), 200
        
    except Exception as e:
        return jsonify({
            'valid': False,
            'error': str(e)
        }), 400


@app.route('/api/health', methods=['GET'])
def health_check():
    return jsonify({
        'status': 'healthy',
        'service': 'Web3 Authentication Service',
        'activeSessions': len(authenticated_sessions),
        'pendingNonces': len(nonces)
    }), 200


if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)